def hash_value(value):
    """Hash sensitive values before storage"""
    return hashlib.sha256(value.encode()).hexdigest()


def verify_hash(value, hashed):
    """Verify a value against its hash"""
    return hashlib.sha256(value.encode()).hexdigest() == hashed


def generate_secure_token():
    """Generate cryptographically secure random token"""
    return secrets.token_urlsafe(32)


def validate_client(client_id, client_secret):
    """Validate client credentials"""
    if not client_id or not client_secret:
        return False
    if client_id not in clients:
        return False
    return verify_hash(client_secret, clients[client_id])


def validate_user(username, password):
    """Validate user credentials"""
    if not username or not password:
        return False
    if username not in users:
        return False
    return verify_hash(password, users[username])


def require_auth(f):
    """Decorator to require valid access token"""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'invalid_token'}), 401
        
        token = auth_header[7:]
        if not token:
            return jsonify({'error': 'invalid_token'}), 401
        
        hashed_token = hash_value(token)
        if hashed_token not in access_tokens:
            return jsonify({'error': 'invalid_token'}), 401
        
        request.user_id = access_tokens[hashed_token]
        return f(*args, **kwargs)
    return decorated


