@app.route('/token', methods=['POST'])
def token():
    """Token endpoint"""
    grant_type = request.form.get('grant_type', '').strip()
    
    if grant_type != 'authorization_code':
        return jsonify({'error': 'unsupported_grant_type'}), 400
    
    # Get parameters
    code = request.form.get('code', '').strip()
    client_id = request.form.get('client_id', '').strip()
    client_secret = request.form.get('client_secret', '').strip()
    redirect_uri = request.form.get('redirect_uri', '').strip()
    
    # Validate client credentials
    if not validate_client(client_id, client_secret):
        return jsonify({'error': 'invalid_client'}), 401
    
    # Validate code
    if not code:
        return jsonify({'error': 'invalid_request'}), 400
    
    hashed_code = hash_value(code)
    
    # Check if code was already exchanged (idempotent retry)
    if hashed_code in used_codes:
        # Return the same token for retry resilience
        return jsonify({
            'access_token': used_codes[hashed_code],
            'token_type': 'Bearer',
            'expires_in': 3600
        })
    
    # Validate authorization code
    if hashed_code not in auth_codes:
        return jsonify({'error': 'invalid_grant'}), 400
    
    user_id = auth_codes[hashed_code]
    
    # Generate access token
    access_token = generate_secure_token()
    hashed_token = hash_value(access_token)
    
    # Store hashed token
    access_tokens[hashed_token] = user_id
    
    # Mark code as used and store token for idempotent retries
    used_codes[hashed_code] = access_token
    
    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': 3600
    })


